# Input: transform_fhir_to_omop (dataframe) - OMOP measurement records output from the FHIR-to-OMOP transform node
# Output: result (dataframe) - Measurement records with resolved person_id and cleaned value_as_number

EQ_VAS_CONCEPT_ID = 42537274


def _unwrap_input_value(value):
    return value.result if hasattr(value, "result") else value


def extract_patient_ref(value):
    if isinstance(value, dict):
        return value.get("reference") or value.get("id") or str(value)
    return str(value) if value is not None else None


def normalize_fhir_id(value):
    if value is None:
        return None
    s = str(value).strip()
    if not s:
        return None
    if "/" in s:
        s = s.split("/")[-1]
    return s


def load_person_id_map(database_code: str, schema_name: str) -> dict[str, int]:
    mapping_schema = f"{database_code}_{schema_name}_fhir_mapping"
    dao = DBDao(
        dialect=SupportedDatabaseDialects.TREX,
        use_cache_db=False,
        database_code=database_code,
    )
    escaped_schema = mapping_schema.replace('"', '""')
    query = f"""
        SELECT fhir_id, omop_id
        FROM "{escaped_schema}"."fhir_omop_key_map"
        WHERE omop_table_name = 'person'
          AND omop_id IS NOT NULL
    """
    rows = dao.execute_sql(query, fetch=True) or []
    result = {}
    for fhir_id, omop_id in rows:
        if fhir_id is None:
            continue
        try:
            omop_int = int(omop_id)
        except Exception:
            continue
        raw_key = str(fhir_id).strip()
        if raw_key:
            result[raw_key] = omop_int
        norm_key = normalize_fhir_id(fhir_id)
        if norm_key:
            result[norm_key] = omop_int
    print(f"[fhir mapping] loaded {len(result)} person mappings from {mapping_schema}.fhir_omop_key_map")
    return result


def exec(myinput):
    data = _unwrap_input_value(myinput.get("transform_fhir_to_omop"))

    if data is None or data.empty:
        return pd.DataFrame()

    if not database_code or not cdm_schema:
        raise ValueError("Missing `database_code` or `cdm_schema`")

    person_id_map = load_person_id_map(database_code, cdm_schema)
    if not person_id_map:
        raise ValueError(
            f"No person mappings found in {database_code}_{cdm_schema}_fhir_mapping.fhir_omop_key_map — "
            "run the person pipeline before the measurement pipeline"
        )

    print(f"[normalize] columns: {list(data.columns)}, rows: {len(data)}")

    result_rows = []
    skipped = []
    for _, row in data.iterrows():
        raw_ref = extract_patient_ref(row.get("person_id"))
        normalized_ref = normalize_fhir_id(raw_ref)
        raw_ref_key = str(raw_ref).strip() if raw_ref is not None else None

        person_id = person_id_map.get(raw_ref_key) or person_id_map.get(normalized_ref)
        if person_id is None:
            skipped.append(raw_ref_key)
            continue

        entry = row.to_dict()
        entry["person_id"] = person_id
        entry["value_as_number"] = entry.get("value_as_number") if entry.get("measurement_concept_id") == EQ_VAS_CONCEPT_ID else None
        result_rows.append(entry)

    if skipped:
        print(f"[normalize] skipped {len(skipped)} rows with no person mapping: {skipped[:10]}")

    if not result_rows:
        raise ValueError(
            f"All {len(data)} rows skipped — no person_id matches found in fhir_omop_key_map. "
            f"Sample unmatched refs: {skipped[:5]}"
        )

    result_df = pd.DataFrame(result_rows)
    print(f"[normalize] output shape: {result_df.shape}")
    return result_df.reset_index(drop=True)
